import { OrbitControls } from '@react-three/drei';
import { Canvas } from '@react-three/fiber';
import * as React from 'react';
import CubeMap from './scene/Cube/CubeMap';
import { LevelsConfig } from './scene/Configs/LevelsConfig';
import { LevelType } from './scene/Enums/LevelType';

export type Props = {};

function App(props: Props) {
  const {} = props;

  const levelConfig = LevelsConfig[LevelType.Level01];
  return (
    <Canvas
      style={{
        border: '1px solid black',
        height: 400,
      }}
      camera={{
        position: [0, 2, 5],
        fov: 75,
        near: 0.1,
        far: 1000,
      }}
    >
      <React.Suspense>
        {/* <Scene /> */}
        {levelConfig && <CubeMap levelConfig={levelConfig} />}
        <OrbitControls enableDamping />
        <ambientLight intensity={0.5} />
        <directionalLight position={[5, 5, 5]} intensity={1} />
      </React.Suspense>
    </Canvas>
  );
}

export default React.memo(App);
