import * as React from 'react';
import { ILevelConfig, IMapConfig } from '../Interfaces/ILevelConfig';
import * as THREE from 'three';
import MapHelper from '../Helpers/MapHelper';
import { CubeSide } from '../Enums/CubeSide';
import MainMaterial from './MainMaterial';
import Corners from './Corners/Corners';
import { Text } from '@react-three/drei';
import Edges from './Edges/Edges';
import EdgesWalls from './EdgesWalls/EdgesWalls';
import Floors from './Floor/Floors';
import Roofs from './Roofs/Roofs';
import Walls from './Walls/Walls';

export type Props = {
  levelConfig: ILevelConfig;
};

const createProcessedMap = (levelConfig: ILevelConfig) => {
  const { sides, edges } = MapHelper.copyMapSidesAndEdges(levelConfig);

  const levelMap: ILevelConfig = {
    size: new THREE.Vector3(levelConfig.size.x, levelConfig.size.y, levelConfig.size.z),
    map: { sides, edges },
  };

  MapHelper.replaceExtraSymbolsInMap(levelMap);
  MapHelper.removeEnemiesIndexesFromMap(levelMap);

  const fullMap: IMapConfig = {};
  Object.values(CubeSide).forEach((side) => {
    fullMap[side] = MapHelper.createFullSideMap(levelMap, side);
  });

  return {
    levelMap,
    fullMap,
  };
};

function CubeMap(props: Props) {
  const { levelConfig } = props;
  const groupRef = React.useRef<THREE.Group>(null);

  // 맵 데이터 처리
  const { levelMap, fullMap } = React.useMemo(() => createProcessedMap(levelConfig), [levelConfig]);
  return (
    <group ref={groupRef}>
      {/* <primitive object={new THREE.BoxGeometry(1, 1, 1)} /> */}

      <Text>HI</Text>
      <Corners levelMap={levelMap} />
      <Edges levelMap={levelMap} />
      <EdgesWalls levelMap={levelMap} />
      <Floors levelMap={levelMap} />
      <Roofs levelMap={levelMap} />
      <Walls levelMap={levelMap} fullMap={fullMap} />
      <MainMaterial />
      <bufferGeometry attach="geometry" />
    </group>
  );
}

export default React.memo(CubeMap);
